using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Adjust the namespace according to your project
using System.Web.Security;

public class ReviewsController : Controller
{
    private readonly YourDbContext _context;

    public ReviewsController()
    {
        _context = new YourDbContext();
    }

    // GET: Reviews/Product/{productId}
    public ActionResult Product(int productId)
    {
        var reviews = _context.Reviews
            .Where(r => r.ProductId == productId)
            .ToList();

        return View(reviews);
    }

    [HttpPost]
    [ValidateAntiForgeryToken]
    public ActionResult SubmitReview(Review review)
    {
        if (ModelState.IsValid)
        {
            review.UserId = User.Identity.GetUserId(); // Assuming you have user authentication
            review.SubmittedAt = DateTime.Now;

            _context.Reviews.Add(review);
            _context.SaveChanges();

            return RedirectToAction("Product", new { productId = review.ProductId });
        }

        return View("Product", new { productId = review.ProductId });
    }
}

// Review Model
public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string UserId { get; set; }
    public string Content { get; set; }
    public DateTime SubmittedAt { get; set; }
}

// Razor View (Product.cshtml)
@model IEnumerable<YourNamespace.Models.Review>

<h2>Product Reviews</h2>

@using (Html.BeginForm("SubmitReview", "Reviews", FormMethod.Post))
{
    @Html.AntiForgeryToken()
    @Html.HiddenFor(m => m.First().ProductId)

    <div>
        @Html.TextAreaFor(m => m.First().Content, new { @placeholder = "Write your review here...", @rows = 5 })
    </div>
    <button type="submit">Submit Review</button>
}

<ul>
    @foreach (var review in Model)
    {
        <li>
            @Html.Raw(review.Content) <br />
            <small>@review.SubmittedAt.ToString("g")</small>
        </li>
    }
</ul>